import sys

class Solution:
    def solve(self, n: int, edges: list[tuple[int, int, int]]) -> int:
        parent = list(range(n + 1))
        rank = [0] * (n + 1)

        def find(x: int) -> int:
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(x: int, y: int) -> bool:
            rx, ry = find(x), find(y)
            if rx == ry:
                return False
            if rank[rx] < rank[ry]:
                parent[rx] = ry
            elif rank[rx] > rank[ry]:
                parent[ry] = rx
            else:
                parent[ry] = rx
                rank[rx] += 1
            return True

        edges_sorted = sorted(edges, key=lambda e: e[2])
        total = 0
        used = 0
        for u, v, w in edges_sorted:
            if union(u, v):
                total += w
                used += 1
                if used == n - 1:
                    break
        return total if used == n - 1 else -1

