#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int solve(int n, vector<array<int,3>>& edges) {
        vector<int> parent(n+1), rankv(n+1,0);
        iota(parent.begin(), parent.end(), 0);
        function<int(int)> find = [&](int x){
            while(parent[x]!=x){
                parent[x]=parent[parent[x]];
                x=parent[x];
            }
            return x;
        };
        auto unite = [&](int a,int b){
            int ra=find(a), rb=find(b);
            if(ra==rb) return false;
            if(rankv[ra]<rankv[rb]) swap(ra,rb);
            parent[rb]=ra;
            if(rankv[ra]==rankv[rb]) rankv[ra]++;
            return true;
        };
        sort(edges.begin(), edges.end(), [](const array<int,3>& a, const array<int,3>& b){return a[2]<b[2];});
        long long total=0; int used=0;
        for(auto &e: edges){
            if(unite(e[0], e[1])){
                total+=e[2];
                if(++used==n-1) break;
            }
        }
        return (used==n-1)? (int)total : -1;
    }
};

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n,m;
    if(!(cin>>n>>m)) return 0;
    vector<array<int,3>> edges;
    edges.reserve(m);
    for(int i=0;i<m;++i){
        int u,v,w;cin>>u>>v>>w;edges.push_back({u,v,w});
    }
    Solution sol;
    int ans=sol.solve(n, edges);
    cout<<ans<<"\n";
    return 0;
}
